179	/// cpu 0.
180	fn spsc_ring_one_msg_1t() -> f64 {
181	    let mut region = Region([0; size_of::<Region>()]);
182	    let (mut producer, mut consumer) = Ring::init(&mut region.0, CACHE_LINE_SIZE as u32, DEPTH)
183	        .unwrap() // OK: Region is sized/aligned for the ring header + DEPTH slots
184	        .split();
185	
186	    let start = Instant::now();
187	    std::thread::scope(|s| {
188	        s.spawn(move || {
189	            pin_to_cpu(0);
190	            for i in 0..COUNT {
191	                match producer.reserve_slot::<Msg>() {
192	                    Ok(mut slot) => {
193	                        slot.seq = i;
194	                        slot.commit();
