                    match producer.reserve_slot::<Desc>() {
                        Ok(mut slot) => {
                            *slot = desc;
                            slot.commit();
                            break;
                        }
                        Err(Full) => std::hint::spin_loop(),
                    }
                }
            }
        });
        s.spawn(move || {
            if let Some((_, c)) = pin {
                pin_to_cpu(c);
            }
            for i in 0..COUNT {
                let desc = loop {
                    match consumer.reserve_slot::<Desc>() {
                        Ok(slot) => {
                            let desc = *slot;
                            slot.release();
                            break desc;
                        }
                        Err(Empty) => std::hint::spin_loop(),
                    }
                };
