//! Probe: two spin-waiting threads pinned to the same cpu,
//! ping-ponging through a depth-64 "ring" (an atomic counter),
//! to estimate the demo's same-cpu timeshared throughput.

use std::sync::atomic::{AtomicU64, Ordering};
use std::time::Instant;

const COUNT: u64 = 100_000;
const DEPTH: u64 = 64;

fn pin_to_cpu(cpu: usize) {
    unsafe {
        let mut set: libc::cpu_set_t = std::mem::zeroed();
        libc::CPU_ZERO(&mut set);
        libc::CPU_SET(cpu, &mut set);
        let rc = libc::sched_setaffinity(0, std::mem::size_of::<libc::cpu_set_t>(), &set);
        assert_eq!(rc, 0);
    }
}

fn main() {
    let head = AtomicU64::new(0);
    let tail = AtomicU64::new(0);
    let start = Instant::now();
    std::thread::scope(|s| {
        s.spawn(|| {
            pin_to_cpu(0);
            for i in 0..COUNT {
                while i - tail.load(Ordering::Acquire) >= DEPTH {
                    std::hint::spin_loop();
                }
                head.store(i + 1, Ordering::Release);
            }
        });
        s.spawn(|| {
            pin_to_cpu(0);
            for i in 0..COUNT {
                while head.load(Ordering::Acquire) <= i {
                    std::hint::spin_loop();
                }
                tail.store(i + 1, Ordering::Release);
            }
        });
    });
    let secs = start.elapsed().as_secs_f64();
    println!(
        "{} msgs in {:.2}s = {:.0} msgs/sec ({:.0} ns/msg)",
        COUNT,
        secs,
        COUNT as f64 / secs,
        secs * 1e9 / COUNT as f64
    );
}

